59→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
60→  const area = polygonArea(points);
61→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
62→  return {
63→    id: generateId('room'),
64→    name,
65→    points: points.map(p => ({ x: p.x, y: p.y })),
66→    labelPosition: { ...centroid },
67→    color,
68→    area,
69→  };
70→}
