  1→import { createContext, useContext, useReducer } from 'react';
  2→import { TOOLS } from '@/editor/tools';
  3→import { DEFAULT_ZOOM } from '@/domain/defaults';
  4→
  5→const EditorContext = createContext(null);
  6→
  7→function editorReducer(state, action) {
  8→  switch (action.type) {
  9→    case 'SET_TOOL':
 10→      return {
 11→        ...state,
 12→        activeTool: action.tool,
 13→        toolState: {},
 14→        selectedId: null,
 15→        selectedType: null,
 16→      };
 17→
 18→    case 'SELECT_OBJECT':
 19→      return {
 20→        ...state,
 21→        selectedId: action.id,
 22→        selectedType: action.objectType,
 23→      };
 24→
 25→    case 'DESELECT':
 26→      return {
 27→        ...state,
 28→        selectedId: null,
 29→        selectedType: null,
 30→      };
 31→
 32→    case 'UPDATE_TOOL_STATE':
 33→      return {
 34→        ...state,
 35→        toolState: { ...state.toolState, ...action.payload },
 36→      };
 37→
 38→    case 'SET_VIEWPORT':
 39→      return {
 40→        ...state,
 41→        viewport: { ...action.viewport },
 42→      };
 43→
 44→    case 'PAN':
 45→      return {
 46→        ...state,
 47→        viewport: {
 48→          ...state.viewport,
 49→          panX: state.viewport.panX + action.dx,
 50→          panY: state.viewport.panY + action.dy,
 51→        },
 52→      };
 53→
 54→    case 'ZOOM': {
 55→      const { zoom, panX, panY } = action;
 56→      return {
 57→        ...state,
 58→        viewport: { zoom, panX, panY },
 59→      };
 60→    }
 61→
 62→    case 'TOGGLE_GRID':
 63→      return { ...state, showGrid: !state.showGrid };
 64→
 65→    case 'TOGGLE_SNAP':
 66→      return { ...state, snapEnabled: !state.snapEnabled };
 67→
 68→    case 'SET_ACTIVE_FLOOR':
 69→      return { ...state, activeFloorId: action.floorId };
 70→
 71→    default:
 72→      return state;
 73→  }
 74→}
